query:
{
  users(
    where: {
      mfaActive: { eq: false }
      OR: [
        {
          iamRoleAssignments_SOME: {
            OR: [
              { internalName_IN: ["Owner", "Contributor"] }
              { isClassicAdministratorAssignment: { eq: true } }
            ]
          }
        }
        {
          groups_SOME: {
            iamRoleAssignments_SOME: {
              OR: [
                { internalName_IN: ["Owner", "Contributor"] }
                { isClassicAdministratorAssignment: { eq: true } }
              ]
            }
          }
        }
      ]
    }
  ) {
    ...AssetFragment
  }
}
